def en_uzun_palindrom_bolge(dizi):
    if not dizi:
        return 0
    en = 1
    def genislet(sol, sag):
        while sol >= 0 and sag < len(dizi) and dizi[sol] == dizi[sag]:
            sol -= 1
            sag += 1
        return sag - sol - 1
    for i in range(len(dizi)):
        en = max(en, genislet(i, i), genislet(i, i + 1))
    return en
